import pytest

from src import auth as auth_module
from src.rate_limiter import RateLimiter


@pytest.fixture(autouse=True)
def _reset_limiter():
    # Each test gets a fresh limiter so attempts from previous tests don't carry over.
    auth_module._login_limiter = RateLimiter(capacity=5, refill_per_second=1 / 30)
    yield


def test_login_success(client, valid_user):
    res = client.post("/auth/login", json={
        "username": valid_user.username,
        "password": valid_user.password,
    })
    assert res.status_code == 200
    assert "token" in res.json


def test_login_bad_password(client, valid_user):
    res = client.post("/auth/login", json={
        "username": valid_user.username,
        "password": "nope",
    })
    assert res.status_code == 401


def test_login_rate_limited_after_burst(client, valid_user):
    bad = {"username": valid_user.username, "password": "nope"}
    # Five bad attempts use up the bucket.
    for _ in range(5):
        assert client.post("/auth/login", json=bad).status_code == 401
    # The sixth comes back as 429, not 401.
    assert client.post("/auth/login", json=bad).status_code == 429
